 80→// --- Group 1: Startup Auth Validation ---
 81→
 82→func TestValidatorSelection(t *testing.T) {
 83→	t.Parallel()
 84→	rsaPEM := generateRSAPEM(t)
 85→
 86→	tests := []struct {
 87→		name         string
 88→		jwtPublicKey string
 89→		jwtSecret    string
 90→		wantErr      bool
 91→		wantType     string // "hmac" or "rsa"
 92→	}{
 93→		{
 94→			name:    "both empty returns error",
 95→			wantErr: true,
 96→		},
 97→		{
 98→			name:      "whitespace secret returns error",
 99→			jwtSecret: "  \t\n",
100→			wantErr:   true,
101→		},
102→		{
103→			name:      "valid secret returns HMAC validator",
104→			jwtSecret: "test-secret-key",
105→			wantType:  "hmac",
106→		},
107→		{
108→			name:         "valid RSA PEM returns RSA validator",
109→			jwtPublicKey: rsaPEM,
110→			wantType:     "rsa",
111→		},
112→		{
113→			name:         "invalid RSA PEM returns error",
114→			jwtPublicKey: "not-a-valid-pem",
115→			wantErr:      true,
116→		},
117→		{
118→			name:         "RSA takes precedence over HMAC",
119→			jwtPublicKey: rsaPEM,
120→			jwtSecret:    "test-secret-key",
121→			wantType:     "rsa",
122→		},
123→	}
124→	for _, tt := range tests {
125→		t.Run(tt.name, func(t *testing.T) {
126→			t.Parallel()
127→			v, err := selectValidator(tt.jwtPublicKey, tt.jwtSecret)
128→			if tt.wantErr {
129→				if err == nil {
130→					t.Fatal("expected error, got nil")
131→				}
132→				return
133→			}
134→			if err != nil {
135→				t.Fatalf("unexpected error: %v", err)
136→			}
137→			switch tt.wantType {
138→			case "hmac":
139→				if _, ok := v.(*auth.HMACValidator); !ok {
140→					t.Errorf("expected *auth.HMACValidator, got %T", v)
141→				}
142→			case "rsa":
143→				if _, ok := v.(*auth.RSAValidator); !ok {
144→					t.Errorf("expected *auth.RSAValidator, got %T", v)
145→				}
146→			}
147→		})
148→	}
