346→
347→			is404 := rr.Code == http.StatusNotFound || rr.Code == http.StatusMethodNotAllowed
348→			if tt.wantExists && is404 {
349→				t.Errorf("route %s %s: status = %d, expected route to exist", tt.method, tt.path, rr.Code)
350→			}
351→			if !tt.wantExists && !is404 {
352→				t.Errorf("route %s %s: status = %d, expected 404/405", tt.method, tt.path, rr.Code)
353→			}
354→		})
355→	}
