10→// protectedResourceMetadata is the JSON response for the OAuth 2.1
11→// Protected Resource Metadata endpoint (RFC 9728). MCP clients use
12→// this to discover how to obtain tokens for the /mcp resource.
13→type protectedResourceMetadata struct {
14→	Resource              string   `json:"resource"`
15→	BearerMethodsSupported []string `json:"bearer_methods_supported"`
16→	AuthorizationServers  []string `json:"authorization_servers,omitempty"`
17→}
18→
19→// ProtectedResourceMetadata returns a handler for
20→// GET /.well-known/oauth-protected-resource per RFC 9728.
21→func ProtectedResourceMetadata(cfg *config.Config) http.HandlerFunc {
22→	return func(w http.ResponseWriter, r *http.Request) {
23→		scheme := "https"
24→		if r.TLS == nil {
25→			scheme = "http"
26→		}
27→		meta := protectedResourceMetadata{
28→			Resource:              scheme + "://" + r.Host + "/mcp",
29→			BearerMethodsSupported: []string{"header"},
30→		}
31→		if cfg.JWTIssuer != "" {
32→			meta.AuthorizationServers = []string{cfg.JWTIssuer}
33→		}
34→		w.Header().Set("Content-Type", "application/json")
35→		_ = json.NewEncoder(w).Encode(meta)
36→	}
37→}
